sql:
SELECT COUNT(DISTINCT artwork_id) AS number_of_masterpieces, AVG(installation_cost) AS average_cost
FROM artworks
WHERE artwork_type_id = 1 AND installation_date LIKE '2022-06-%';

SELECT location, ward, shelter, number_of_benches
FROM bus_stops
WHERE ward = 'Downtown';

external_knowledge:
- Sculptures and paintings are types of artworks; 
- Installation cost refers to the cost of installing an artwork; 
- Artist id 0 might refer to a specific artist or a default/anonymous artist in the database.

sql:
WITH highest_population_ward AS (
  SELECT ward_id FROM wards ORDER BY population DESC LIMIT 1
)

SELECT bs.location AS bus_stop_location
FROM bus_stops bs
INNER JOIN highest_population_ward hpw ON bs.ward = hpw.ward_id;

SELECT title 
FROM artworks 
WHERE installation_cost = (SELECT MAX(installation_cost) FROM artworks);

SELECT title, installation_date
FROM artworks
WHERE installation_date = (SELECT MAX(installation_date) FROM artworks);

SELECT COUNT(report_id) AS report_count
FROM reports
WHERE artwork_id = (SELECT artwork_id FROM artworks WHERE title = 'Abstract Dreams');

SELECT COUNT(*) 
FROM bus_stops 
WHERE ward = 1;
